pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

/**
 * @title AuditableVault
 * @dev Vault contract with comprehensive event logging for non-repudiation
 */
contract AuditableVault is AccessControl, ReentrancyGuard {
    bytes32 public constant WITHDRAWER_ROLE = keccak256("WITHDRAWER_ROLE");

    // Comprehensive event definitions with indexed parameters
    event Deposit(
        address indexed depositor,
        uint256 indexed amount,
        uint256 newBalance,
        uint256 timestamp,
        bytes32 transactionHash
    );

    event Withdrawal(
        address indexed withdrawer,
        address indexed recipient,
        uint256 indexed amount,
        uint256 remainingBalance,
        uint256 timestamp,
        bytes32 transactionHash,
        string reason
    );

    event WithdrawalApproved(
        address indexed approver,
        address indexed withdrawer,
        uint256 amount,
        uint256 timestamp,
        bytes32 approvalHash
    );

    event RoleGrantedWithAudit(
        bytes32 indexed role,
        address indexed account,
        address indexed grantedBy,
        uint256 timestamp,
        string justification
    );

    event StateChangeDetected(
        string functionName,
        address indexed caller,
        bytes32 previousStateHash,
        bytes32 newStateHash,
        uint256 timestamp
    );

    mapping(address => uint256) public balances;
    mapping(bytes32 => bool) public processedTransactions;

    constructor() {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        emit RoleGrantedWithAudit(
            DEFAULT_ADMIN_ROLE,
            msg.sender,
            msg.sender,
            block.timestamp,
            "Contract deployment"
        );
    }

    /**
     * @dev Deposit funds with full audit trail
     */
    function deposit() external payable {
        require(msg.value > 0, "Deposit must be greater than 0");

        bytes32 previousState = keccak256(abi.encodePacked(balances[msg.sender]));

        balances[msg.sender] += msg.value;

        bytes32 txHash = keccak256(abi.encodePacked(
            msg.sender,
            msg.value,
            block.timestamp,
            block.number
        ));

        emit Deposit(
            msg.sender,
            msg.value,
            balances[msg.sender],
            block.timestamp,
            txHash
        );

        emit StateChangeDetected(
            "deposit",
            msg.sender,
            previousState,
            keccak256(abi.encodePacked(balances[msg.sender])),
            block.timestamp
        );
    }

    /**
     * @dev Withdraw with multi-event logging and approval tracking
     */
    function withdraw(
        uint256 amount,
        address recipient,
        string calldata reason
    ) external nonReentrant onlyRole(WITHDRAWER_ROLE) {
        require(amount > 0, "Amount must be greater than 0");
        require(balances[msg.sender] >= amount, "Insufficient balance");
        require(recipient != address(0), "Invalid recipient");

        // Generate unique transaction hash for replay protection
        bytes32 txHash = keccak256(abi.encodePacked(
            msg.sender,
            recipient,
            amount,
            block.timestamp,
            block.number
        ));

        require(!processedTransactions[txHash], "Transaction already processed");
        processedTransactions[txHash] = true;

        bytes32 previousState = keccak256(abi.encodePacked(balances[msg.sender]));

        balances[msg.sender] -= amount;

        // Emit approval event BEFORE transfer
        emit WithdrawalApproved(
            msg.sender,
            msg.sender,
            amount,
            block.timestamp,
            txHash
        );

        (bool success, ) = recipient.call{value: amount}("");
        require(success, "Transfer failed");

        // Emit comprehensive withdrawal event AFTER successful transfer
        emit Withdrawal(
            msg.sender,
            recipient,
            amount,
            balances[msg.sender],
            block.timestamp,
            txHash,
            reason
        );

        emit StateChangeDetected(
            "withdraw",
            msg.sender,
            previousState,
            keccak256(abi.encodePacked(balances[msg.sender])),
            block.timestamp
        );
    }

    /**
     * @dev Override role granting with audit events
     */
    function grantRoleWithJustification(
        bytes32 role,
        address account,
        string calldata justification
    ) external onlyRole(DEFAULT_ADMIN_ROLE) {
        _grantRole(role, account);

        emit RoleGrantedWithAudit(
            role,
            account,
            msg.sender,
            block.timestamp,
            justification
        );
    }

    /**
     * @dev Emergency pause with full audit trail
     */
    event EmergencyAction(
        string action,
        address indexed initiator,
        uint256 timestamp,
        string reason,
        bytes32 stateSnapshot
    );

    function emergencyPause(string calldata reason) external onlyRole(DEFAULT_ADMIN_ROLE) {
        bytes32 stateSnapshot = keccak256(abi.encodePacked(
            address(this).balance,
            block.timestamp
        ));

        emit EmergencyAction(
            "PAUSE",
            msg.sender,
            block.timestamp,
            reason,
            stateSnapshot
        );

        // Pause logic here
    }
}

