'use strict';

const { Contract } = require('fabric-contract-api');
const crypto = require('crypto');

/**
 * AuditableAssetContract with comprehensive transaction logging
 */
class AuditableAssetContract extends Contract {

    /**
     * Initialize ledger with audit trail structure
     */
    async initLedger(ctx) {
        console.info('============= START : Initialize Ledger ===========');

        // Store audit configuration
        const auditConfig = {
            docType: 'auditConfig',
            version: '1.0.0',
            retentionPeriod: 7 * 365 * 24 * 60 * 60 * 1000, // 7 years in ms
            requiredFields: ['timestamp', 'actor', 'action', 'assetId', 'transactionId'],
            createdAt: new Date().toISOString(),
            createdBy: ctx.clientIdentity.getID()
        };

        await ctx.stub.putState('AUDIT_CONFIG', Buffer.from(JSON.stringify(auditConfig)));

        console.info('============= END : Initialize Ledger ===========');
    }

    /**
     * Create asset with full audit trail
     */
    async createAsset(ctx, assetId, owner, value, metadata) {
        console.info('============= START : Create Asset ===========');

        // Validate input
        if (!assetId || !owner || !value) {
            throw new Error('Asset ID, owner, and value are required');
        }

        // Get transaction metadata
        const txId = ctx.stub.getTxID();
        const timestamp = ctx.stub.getTxTimestamp();
        const mspId = ctx.clientIdentity.getMSPID();
        const clientId = ctx.clientIdentity.getID();
        const clientCert = ctx.clientIdentity.getX509Certificate();

        // Create asset with audit fields
        const asset = {
            docType: 'asset',
            assetId: assetId,
            owner: owner,
            value: value,
            metadata: metadata,
            createdAt: new Date(timestamp.seconds * 1000).toISOString(),
            createdBy: clientId,
            createdByMSP: mspId,
            createdTxId: txId,
            lastModified: new Date(timestamp.seconds * 1000).toISOString(),
            lastModifiedBy: clientId,
            version: 1
        };

        // Store asset
        await ctx.stub.putState(assetId, Buffer.from(JSON.stringify(asset)));

        // Create audit log entry with composite key
        const auditLogKey = ctx.stub.createCompositeKey('auditLog', [
            assetId,
            txId,
            timestamp.seconds.toString()
        ]);

        const auditLog = {
            docType: 'auditLog',
            assetId: assetId,
            action: 'CREATE',
            actor: clientId,
            actorMSP: mspId,
            actorCertHash: crypto.createHash('sha256').update(clientCert.getSerialNumber()).digest('hex'),
            timestamp: new Date(timestamp.seconds * 1000).toISOString(),
            transactionId: txId,
            channelId: ctx.stub.getChannelID(),
            previousValue: null,
            newValue: value,
            metadata: {
                endorsements: ctx.stub.getSignedProposal().proposal.header.signature_header,
                clientIdentity: {
                    mspId: mspId,
                    id: clientId,
                    certIssuer: clientCert.issuer.organizationName
                }
            }
        };

        await ctx.stub.putState(auditLogKey, Buffer.from(JSON.stringify(auditLog)));

        // Emit event for off-chain systems
        const eventPayload = {
            type: 'AssetCreated',
            assetId: assetId,
            owner: owner,
            value: value,
            transactionId: txId,
            timestamp: auditLog.timestamp,
            actor: clientId
        };

        await ctx.stub.setEvent('AssetCreated', Buffer.from(JSON.stringify(eventPayload)));

        console.info('============= END : Create Asset ===========');
        return JSON.stringify(asset);
    }

    /**
     * Transfer asset with audit trail
     */
    async transferAsset(ctx, assetId, newOwner, reason) {
        console.info('============= START : Transfer Asset ===========');

        // Get existing asset
        const assetBytes = await ctx.stub.getState(assetId);
        if (!assetBytes || assetBytes.length === 0) {
            throw new Error(`Asset ${assetId} does not exist`);
        }

        const asset = JSON.parse(assetBytes.toString());
        const previousOwner = asset.owner;

        // Get transaction metadata
        const txId = ctx.stub.getTxID();
        const timestamp = ctx.stub.getTxTimestamp();
        const clientId = ctx.clientIdentity.getID();
        const mspId = ctx.clientIdentity.getMSPID();

        // Verify ownership or authorized role
        if (asset.owner !== clientId) {
            const isAuthorized = await this._checkTransferAuthorization(ctx, clientId);
            if (!isAuthorized) {
                throw new Error(`Client ${clientId} is not authorized to transfer asset ${assetId}`);
            }
        }

        // Update asset
        asset.owner = newOwner;
        asset.lastModified = new Date(timestamp.seconds * 1000).toISOString();
        asset.lastModifiedBy = clientId;
        asset.version += 1;

        await ctx.stub.putState(assetId, Buffer.from(JSON.stringify(asset)));

        // Create audit log with transfer details
        const auditLogKey = ctx.stub.createCompositeKey('auditLog', [
            assetId,
            txId,
            timestamp.seconds.toString()
        ]);

        const auditLog = {
            docType: 'auditLog',
            assetId: assetId,
            action: 'TRANSFER',
            actor: clientId,
            actorMSP: mspId,
            timestamp: new Date(timestamp.seconds * 1000).toISOString(),
            transactionId: txId,
            channelId: ctx.stub.getChannelID(),
            previousValue: previousOwner,
            newValue: newOwner,
            reason: reason,
            metadata: {
                assetVersion: asset.version,
                endorsementSignatures: ctx.stub.getSignedProposal().proposal.header.signature_header
            }
        };

        await ctx.stub.putState(auditLogKey, Buffer.from(JSON.stringify(auditLog)));

        // Emit transfer event
        const eventPayload = {
            type: 'AssetTransferred',
            assetId: assetId,
            previousOwner: previousOwner,
            newOwner: newOwner,
            transactionId: txId,
            timestamp: auditLog.timestamp,
            actor: clientId,
            reason: reason
        };

        await ctx.stub.setEvent('AssetTransferred', Buffer.from(JSON.stringify(eventPayload)));

        console.info('============= END : Transfer Asset ===========');
        return JSON.stringify(asset);
    }

    /**
     * Query audit logs for specific asset
     */
    async queryAuditLogs(ctx, assetId, startTime, endTime) {
        console.info('============= START : Query Audit Logs ===========');

        // Build CouchDB rich query
        const query = {
            selector: {
                docType: 'auditLog',
                assetId: assetId,
                timestamp: {
                    $gte: startTime,
                    $lte: endTime
                }
            },
            sort: [{ timestamp: 'desc' }],
            use_index: ['_design/auditLogIndexDoc', 'auditLogIndex']
        };

        const iterator = await ctx.stub.getQueryResult(JSON.stringify(query));
        const results = [];

        let result = await iterator.next();
        while (!result.done) {
            const auditLog = JSON.parse(result.value.value.toString());
            results.push(auditLog);
            result = await iterator.next();
        }

        await iterator.close();

        console.info('============= END : Query Audit Logs ===========');
        return JSON.stringify(results);
    }

    /**
     * Get transaction history for asset (immutable audit trail)
     */
    async getAssetHistory(ctx, assetId) {
        console.info('============= START : Get Asset History ===========');

        const iterator = await ctx.stub.getHistoryForKey(assetId);
        const history = [];

        let result = await iterator.next();
        while (!result.done) {
            const txId = result.value.txId;
            const timestamp = result.value.timestamp;
            const isDelete = result.value.isDelete;

            const historyEntry = {
                transactionId: txId,
                timestamp: new Date(timestamp.seconds * 1000).toISOString(),
                isDelete: isDelete,
                value: isDelete ? null : JSON.parse(result.value.value.toString())
            };

            history.push(historyEntry);
            result = await iterator.next();
        }

        await iterator.close();

        console.info('============= END : Get Asset History ===========');
        return JSON.stringify(history);
    }

    /**
     * Verify transaction authenticity using endorsement signatures
     */
    async verifyTransactionAuthenticity(ctx, transactionId) {
        const txBytes = await ctx.stub.getState(`TX_${transactionId}`);
        if (!txBytes || txBytes.length === 0) {
            return { verified: false, reason: 'Transaction not found' };
        }

        const tx = JSON.parse(txBytes.toString());

        // Verify endorsement policy was satisfied
        const endorsements = ctx.stub.getSignedProposal().proposal.header.signature_header;

        return {
            verified: true,
            transactionId: transactionId,
            endorsements: endorsements,
            channelId: ctx.stub.getChannelID(),
            timestamp: tx.timestamp
        };
    }

    async _checkTransferAuthorization(ctx, clientId) {
        // Check if client has 'transferer' attribute
        return ctx.clientIdentity.assertAttributeValue('transferer', 'true');
    }
}

module.exports = AuditableAssetContract;

/**
 * Comprehensive transaction receipt verification and archival system
 * Provides cryptographic proof of transaction execution for audit trails
