const { ethers } = require('ethers');
const crypto = require('crypto');
const axios = require('axios');

/**
 * TransactionAuditService - Handles receipt verification and archival
 */
class TransactionAuditService {
    constructor(providerUrl, ipfsEndpoint, arweaveWallet) {
        this.provider = new ethers.JsonRpcProvider(providerUrl);
        this.ipfsEndpoint = ipfsEndpoint || 'https://ipfs.infura.io:5001/api/v0';
        this.arweaveWallet = arweaveWallet;
    }

    /**
     * Execute transaction with full audit trail
     */
    async executeWithAudit(signer, contractAddress, contractABI, functionName, args, metadata) {
        const contract = new ethers.Contract(contractAddress, contractABI, signer);

        console.log(`[AUDIT] Executing ${functionName} with args:`, args);

        // Create pre-transaction audit record
        const preAudit = {
            timestamp: new Date().toISOString(),
            actor: await signer.getAddress(),
            contract: contractAddress,
            function: functionName,
            arguments: args,
            metadata: metadata,
            nonce: await signer.getNonce(),
            chainId: (await this.provider.getNetwork()).chainId
        };

        // Execute transaction
        const tx = await contract[functionName](...args);

        console.log(`[AUDIT] Transaction sent: ${tx.hash}`);

        // Wait for confirmation with timeout
        const receipt = await this._waitForReceiptWithRetry(tx.hash, 5, 60000);

        if (!receipt) {
            throw new Error(`Transaction ${tx.hash} failed to confirm within timeout`);
        }

        // Build comprehensive audit record
        const auditRecord = await this._buildAuditRecord(receipt, preAudit, tx);

        // Store audit record in decentralized storage
        const ipfsCID = await this._storeOnIPFS(auditRecord);

        console.log(`[AUDIT] Audit record stored on IPFS: ${ipfsCID}`);

        // Optionally anchor to Arweave for permanent storage
        if (this.arweaveWallet) {
            const arweaveTx = await this._storeOnArweave(auditRecord);
            console.log(`[AUDIT] Audit record anchored on Arweave: ${arweaveTx}`);
        }

        return {
            transactionHash: tx.hash,
            receipt: receipt,
            auditRecord: auditRecord,
            ipfsCID: ipfsCID,
            verified: await this._verifyCryptographicProof(receipt)
        };
    }

    /**
     * Build comprehensive audit record from transaction receipt
     */
    async _buildAuditRecord(receipt, preAudit, tx) {
        // Get full transaction details
        const transaction = await this.provider.getTransaction(receipt.hash);
        const block = await this.provider.getBlock(receipt.blockNumber);

        // Extract event logs
        const events = receipt.logs.map(log => ({
            address: log.address,
            topics: log.topics,
            data: log.data,
            logIndex: log.index,
            blockNumber: log.blockNumber,
            transactionHash: log.transactionHash
        }));

        // Create audit record
        const auditRecord = {
            version: '1.0.0',
            recordType: 'ethereum-transaction-audit',
            createdAt: new Date().toISOString(),

            // Pre-transaction data
            preTransaction: preAudit,

            // Transaction data
            transaction: {
                hash: transaction.hash,
                from: transaction.from,
                to: transaction.to,
                value: transaction.value.toString(),
                data: transaction.data,
                nonce: transaction.nonce,
                gasLimit: transaction.gasLimit.toString(),
                gasPrice: transaction.gasPrice ? transaction.gasPrice.toString() : null,
                maxFeePerGas: transaction.maxFeePerGas ? transaction.maxFeePerGas.toString() : null,
                maxPriorityFeePerGas: transaction.maxPriorityFeePerGas ? transaction.maxPriorityFeePerGas.toString() : null,
                chainId: transaction.chainId.toString(),
                type: transaction.type,
                signature: {
                    r: transaction.signature.r,
                    s: transaction.signature.s,
                    v: transaction.signature.v
                }
            },

            // Receipt data (cryptographic proof)
            receipt: {
                transactionHash: receipt.hash,
                transactionIndex: receipt.index,
                blockHash: receipt.blockHash,
                blockNumber: receipt.blockNumber,
                from: receipt.from,
                to: receipt.to,
                cumulativeGasUsed: receipt.cumulativeGasUsed.toString(),
                gasUsed: receipt.gasUsed.toString(),
                contractAddress: receipt.contractAddress,
                status: receipt.status,
                logsBloom: receipt.logsBloom,
                logs: events,
                effectiveGasPrice: receipt.gasPrice ? receipt.gasPrice.toString() : null
            },

            // Block context
            block: {
                number: block.number,
                hash: block.hash,
                timestamp: block.timestamp,
                miner: block.miner,
                difficulty: block.difficulty ? block.difficulty.toString() : null,
                parentHash: block.parentHash,
                stateRoot: block.stateRoot,
                transactionsRoot: block.transactionsRoot,
                receiptsRoot: block.receiptsRoot
            },

            // Verification data
            verification: {
                receiptRootHash: this._calculateReceiptRootHash(receipt),
                merkleProof: await this._generateMerkleProof(receipt),
                nodeProvider: this.provider._getConnection().url,
                verifiedAt: new Date().toISOString()
            }
        };

        // Add cryptographic hash of entire record
        auditRecord.recordHash = this._hashAuditRecord(auditRecord);

        return auditRecord;
    }

    /**
     * Wait for transaction receipt with retry logic
     */
    async _waitForReceiptWithRetry(txHash, confirmations = 5, timeout = 60000) {
        const startTime = Date.now();

        while (Date.now() - startTime < timeout) {
            try {
                const receipt = await this.provider.getTransactionReceipt(txHash);

                if (receipt && receipt.blockNumber) {
                    const currentBlock = await this.provider.getBlockNumber();
                    const confirmationCount = currentBlock - receipt.blockNumber;

                    if (confirmationCount >= confirmations) {
                        console.log(`[AUDIT] Transaction confirmed with ${confirmationCount} confirmations`);
                        return receipt;
                    }

                    console.log(`[AUDIT] Waiting for confirmations: ${confirmationCount}/${confirmations}`);
                }
            } catch (error) {
                console.error('[AUDIT] Error fetching receipt:', error.message);
            }

            await new Promise(resolve => setTimeout(resolve, 2000));
        }

        return null;
    }

    /**
     * Verify cryptographic proof of transaction execution
     */
    async _verifyCryptographicProof(receipt) {
        try {
            // Verify receipt exists in block
            const block = await this.provider.getBlock(receipt.blockNumber, true);

            if (!block) {
                return { verified: false, reason: 'Block not found' };
            }

            // Verify transaction hash exists in block
            const txInBlock = block.transactions.find(tx => {
                if (typeof tx === 'string') {
                    return tx === receipt.hash;
                }
                return tx.hash === receipt.hash;
            });

            if (!txInBlock) {
                return { verified: false, reason: 'Transaction not found in block' };
            }

            // Verify receipt root hash matches block's receiptsRoot
            // Note: Full verification requires Merkle proof, simplified here
            return {
                verified: true,
                blockHash: receipt.blockHash,
                blockNumber: receipt.blockNumber,
                receiptsRoot: block.receiptsRoot,
                confirmations: (await this.provider.getBlockNumber()) - receipt.blockNumber
            };
        } catch (error) {
            return { verified: false, reason: error.message };
        }
    }

    /**
     * Store audit record on IPFS
     */
    async _storeOnIPFS(auditRecord) {
        try {
            const response = await axios.post(
                `${this.ipfsEndpoint}/add`,
                JSON.stringify(auditRecord, null, 2),
                {
                    headers: { 'Content-Type': 'application/json' }
                }
            );

            return response.data.Hash;
        } catch (error) {
            console.error('[AUDIT] Failed to store on IPFS:', error.message);
            return null;
        }
    }

    /**
     * Store audit record on Arweave for permanent storage
     */
    async _storeOnArweave(auditRecord) {
        // Simplified - requires Arweave SDK integration
        console.log('[AUDIT] Arweave storage not implemented in this example');
        return null;
    }

    /**
     * Calculate receipt root hash
     */
    _calculateReceiptRootHash(receipt) {
        const receiptData = JSON.stringify({
            blockHash: receipt.blockHash,
            blockNumber: receipt.blockNumber,
            transactionHash: receipt.hash,
            status: receipt.status
        });

        return crypto.createHash('sha256').update(receiptData).digest('hex');
    }

    /**
     * Generate Merkle proof for receipt (simplified)
     */
    async _generateMerkleProof(receipt) {
        // Full implementation requires Merkle Patricia Trie
        // Simplified version returns receipt hash
        return {
            receiptHash: receipt.hash,
            blockHash: receipt.blockHash,
            proof: 'Merkle proof generation requires full trie implementation'
        };
    }

    /**
     * Hash entire audit record for tamper detection
     */
    _hashAuditRecord(record) {
        const recordCopy = { ...record };
        delete recordCopy.recordHash; // Exclude hash field itself

        const recordString = JSON.stringify(recordCopy, Object.keys(recordCopy).sort());
        return crypto.createHash('sha256').update(recordString).digest('hex');
    }

    /**
     * Retrieve and verify audit record from IPFS
     */
    async retrieveAuditRecord(ipfsCID) {
        try {
            const response = await axios.post(
                `${this.ipfsEndpoint}/cat?arg=${ipfsCID}`
            );

            const auditRecord = response.data;

            // Verify record hash
            const calculatedHash = this._hashAuditRecord(auditRecord);

            if (calculatedHash !== auditRecord.recordHash) {
                return {
                    valid: false,
                    reason: 'Audit record hash mismatch - possible tampering'
                };
            }

            return {
                valid: true,
                auditRecord: auditRecord
            };
        } catch (error) {
            return {
                valid: false,
                reason: `Failed to retrieve from IPFS: ${error.message}`
            };
        }
    }
}

