pragma solidity ^0.8.20;

import "@chainlink/contracts/src/v0.8/interfaces/AggregatorV3Interface.sol";
import "@chainlink/contracts/src/v0.8/VRFConsumerBaseV2.sol";
import "@chainlink/contracts/src/v0.8/interfaces/VRFCoordinatorV2Interface.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";

/**
 * @title OracleAuditableContract
 * @dev Contract with comprehensive oracle data audit trail
 */
contract OracleAuditableContract is VRFConsumerBaseV2, AccessControl {
    bytes32 public constant ORACLE_ADMIN_ROLE = keccak256("ORACLE_ADMIN_ROLE");

    VRFCoordinatorV2Interface public immutable vrfCoordinator;
    AggregatorV3Interface public priceFeed;

    uint64 public subscriptionId;
    bytes32 public keyHash;
    uint32 public callbackGasLimit = 200000;
    uint16 public requestConfirmations = 3;

    // Comprehensive oracle data audit structure
    struct OracleDataAttestation {
        uint80 roundId;
        int256 answer;
        uint256 startedAt;
        uint256 updatedAt;
        uint80 answeredInRound;
        address requestedBy;
        uint256 blockNumber;
        bytes32 dataHash;
        bool verified;
        bytes signature; // Oracle signature for non-repudiation
    }

    struct VRFAttestation {
        uint256 requestId;
        uint256 randomWord;
        uint256 blockNumber;
        address requester;
        bytes32 requestHash;
        bool fulfilled;
    }

    // Storage mappings
    mapping(uint256 => OracleDataAttestation) public oracleAttestations;
    mapping(uint256 => VRFAttestation) public vrfAttestations;
    mapping(bytes32 => bool) public processedDataHashes;

    uint256 public attestationCounter;
    uint256 public vrfCounter;

    // Comprehensive events for audit trail
    event OracleDataRequested(
        uint256 indexed attestationId,
        address indexed requester,
        uint256 timestamp,
        bytes32 dataHash
    );

    event OracleDataReceived(
        uint256 indexed attestationId,
        uint80 indexed roundId,
        int256 answer,
        uint256 updatedAt,
        bytes32 dataHash,
        bool verified
    );

    event VRFRequested(
        uint256 indexed requestId,
        address indexed requester,
        uint256 timestamp,
        bytes32 requestHash
    );

    event VRFFulfilled(
        uint256 indexed requestId,
        uint256 randomWord,
        uint256 blockNumber
    );

    event OracleDataManipulationDetected(
        uint256 attestationId,
        string reason,
        bytes32 suspiciousDataHash
    );

    constructor(
        address _priceFeed,
        address _vrfCoordinator,
        uint64 _subscriptionId,
        bytes32 _keyHash
    ) VRFConsumerBaseV2(_vrfCoordinator) {
        priceFeed = AggregatorV3Interface(_priceFeed);
        vrfCoordinator = VRFCoordinatorV2Interface(_vrfCoordinator);
        subscriptionId = _subscriptionId;
        keyHash = _keyHash;

        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ORACLE_ADMIN_ROLE, msg.sender);
    }

    /**
     * @dev Request and attest price data with full audit trail
     */
    function requestAndAttestPriceData() external returns (uint256) {
        uint256 attestationId = attestationCounter++;

        // Get latest round data from Chainlink
        (
            uint80 roundId,
            int256 answer,
            uint256 startedAt,
            uint256 updatedAt,
            uint80 answeredInRound
        ) = priceFeed.latestRoundData();

        // Validate data freshness (within 1 hour)
        require(updatedAt > block.timestamp - 3600, "Stale oracle data");
        require(answeredInRound >= roundId, "Stale round");
        require(answer > 0, "Invalid price");

        // Calculate data hash for tamper detection
        bytes32 dataHash = keccak256(abi.encodePacked(
            roundId,
            answer,
            updatedAt,
            msg.sender,
            block.number
        ));

        // Check for replay attacks
        require(!processedDataHashes[dataHash], "Duplicate data hash");
        processedDataHashes[dataHash] = true;

        // Create attestation record
        OracleDataAttestation memory attestation = OracleDataAttestation({
            roundId: roundId,
            answer: answer,
            startedAt: startedAt,
            updatedAt: updatedAt,
            answeredInRound: answeredInRound,
            requestedBy: msg.sender,
            blockNumber: block.number,
            dataHash: dataHash,
            verified: true,
            signature: "" // In production, get from oracle signature
        });

        oracleAttestations[attestationId] = attestation;

        emit OracleDataRequested(
            attestationId,
            msg.sender,
            block.timestamp,
            dataHash
        );

        emit OracleDataReceived(
            attestationId,
            roundId,
            answer,
            updatedAt,
            dataHash,
            true
        );

        return attestationId;
    }

    /**
     * @dev Request verifiable random number with audit trail
     */
    function requestRandomnessWithAttestation() external returns (uint256) {
        uint256 requestId = vrfCoordinator.requestRandomWords(
            keyHash,
            subscriptionId,
            requestConfirmations,
            callbackGasLimit,
            1 // numWords
        );

        bytes32 requestHash = keccak256(abi.encodePacked(
            requestId,
            msg.sender,
            block.number,
            block.timestamp
        ));

        vrfAttestations[requestId] = VRFAttestation({
            requestId: requestId,
            randomWord: 0,
            blockNumber: block.number,
            requester: msg.sender,
            requestHash: requestHash,
            fulfilled: false
        });

        emit VRFRequested(
            requestId,
            msg.sender,
            block.timestamp,
            requestHash
        );

        return requestId;
    }

    /**
     * @dev VRF callback with attestation storage
     */
    function fulfillRandomWords(
        uint256 requestId,
        uint256[] memory randomWords
    ) internal override {
        require(vrfAttestations[requestId].requestId == requestId, "Invalid request");
        require(!vrfAttestations[requestId].fulfilled, "Already fulfilled");

        vrfAttestations[requestId].randomWord = randomWords[0];
        vrfAttestations[requestId].fulfilled = true;

        emit VRFFulfilled(
            requestId,
            randomWords[0],
            block.number
        );
    }

    /**
     * @dev Verify oracle data attestation integrity
     */
    function verifyAttestation(uint256 attestationId) external view returns (bool, string memory) {
        OracleDataAttestation memory attestation = oracleAttestations[attestationId];

        if (attestation.blockNumber == 0) {
            return (false, "Attestation not found");
        }

        // Recalculate data hash
        bytes32 calculatedHash = keccak256(abi.encodePacked(
            attestation.roundId,
            attestation.answer,
            attestation.updatedAt,
            attestation.requestedBy,
            attestation.blockNumber
        ));

        if (calculatedHash != attestation.dataHash) {
            return (false, "Data hash mismatch - possible tampering");
        }

        // Verify data is not stale
        if (block.timestamp - attestation.updatedAt > 3600) {
            return (false, "Attestation data is stale");
        }

        return (true, "Attestation verified");
    }

    /**
     * @dev Get full attestation audit trail
     */
    function getAttestationAuditTrail(uint256 attestationId) 
        external 
        view 
        returns (
            uint80 roundId,
            int256 answer,
            uint256 updatedAt,
            address requester,
            bytes32 dataHash,
            bool verified
        ) 
    {
        OracleDataAttestation memory attestation = oracleAttestations[attestationId];

        return (
            attestation.roundId,
            attestation.answer,
            attestation.updatedAt,
            attestation.requestedBy,
            attestation.dataHash,
            attestation.verified
        );
    }

    /**
     * @dev Detect potential oracle manipulation
     */
    function detectOracleManipulation(uint256 attestationId) external {
        OracleDataAttestation memory current = oracleAttestations[attestationId];

        if (attestationId == 0) return;

        OracleDataAttestation memory previous = oracleAttestations[attestationId - 1];

        // Check for suspicious price jumps (>50% in single update)
        if (previous.answer > 0) {
            int256 priceChange = ((current.answer - previous.answer) * 100) / previous.answer;

            if (priceChange > 50 || priceChange < -50) {
                emit OracleDataManipulationDetected(
                    attestationId,
                    "Suspicious price jump detected",
                    current.dataHash
                );
            }
        }

        // Check for rapid updates (< 60 seconds)
        if (current.updatedAt - previous.updatedAt < 60) {
            emit OracleDataManipulationDetected(
                attestationId,
                "Rapid update frequency detected",
                current.dataHash
            );
        }
    }

    /**
     * @dev Update price feed address (admin only)
     */
    function updatePriceFeed(address newPriceFeed) 
        external 
        onlyRole(ORACLE_ADMIN_ROLE) 
    {
        require(newPriceFeed != address(0), "Invalid price feed");
        priceFeed = AggregatorV3Interface(newPriceFeed);
    }
}
